@AccessControl.authorizationCheck: #CHECK
define view ZCDS_SALES_ORG_ORDERS
  as select from vbak { key vbeln, vkorg, kunnr }

" DCL source: ZCDS_SALES_ORG_ORDERS
@MappingRole: true
define role ZCDS_SALES_ORG_ORDERS {
  grant select on ZCDS_SALES_ORG_ORDERS
  where (vkorg) = aspect pfcg_auth(V_VBAK_VKO,
                                   VKORG, ACTVT = '03');
}

@OData.publish: true
@UI.headerInfo: { typeName: 'Purchase Order',
                  typeNamePlural: 'Purchase Orders' }
define view ZCDS_PO_HEADER
  as select from ekko
{
  @UI.lineItem: [{ position: 10 }]
  @UI.selectionField: [{ position: 10 }]
  key ekko.ebeln as PurchaseOrder,
  @UI.lineItem: [{ position: 20 }]
      ekko.lifnr as Vendor,
  @UI.lineItem: [{ position: 30 }]
      ekko.bedat as DocumentDate
}

" Interface View - stable data model
define view ZI_SALES_ORDER
  as select from vbak
  association [0..*] to vbap as _Items
    on $projection.vbeln = _Items.vbeln
{ key vbak.vbeln, vbak.kunnr, _Items }

" Consumption View - Fiori specific
@UI.headerInfo: { typeName: 'Sales Order' }
define view ZC_SALES_ORDER_LIST
  as select from ZI_SALES_ORDER
{
  @UI.lineItem: [{ position: 10 }]
  key vbeln,
  @UI.lineItem: [{ position: 20 }]
      kunnr
}

@Analytics.dataCategory: #CUBE
@Analytics.query: true
define view ZCDS_REVENUE_CUBE
  as select from acdoca
{
  key acdoca.rldnr,
  key acdoca.rbukrs as CompanyCode,
  key acdoca.gjahr  as FiscalYear,
  key acdoca.prctr  as ProfitCenter,
  @Aggregation.default: #SUM
  @Semantics.amount.currencyCode: 'Currency'
      sum(acdoca.hsl) as Amount,
      acdoca.rhcur    as Currency
} group by acdoca.rldnr, acdoca.rbukrs,
           acdoca.gjahr, acdoca.prctr, acdoca.rhcur

" CDS View (data model - read)
define view entity ZI_VENDOR_RAP
  as select from lfa1
{ key lfa1.lifnr, lfa1.name1, lfa1.land1 }

" Behavior Definition (write operations)
managed implementation in class
  zbp_i_vendor_rap unique;
strict ( 2 );
define behavior for ZI_VENDOR_RAP alias Vendor
persistent table lfa1
{
  create; update; delete;
  field ( readonly ) Lifnr;
  validation validateCountry
    on save { field Land1; }
}

@AbapCatalog.sqlViewName: 'ZMAT_V'    " Max 16 chars
@EndUserText.label: 'Material View'
define view ZCDS_MATERIAL_HEADER      " CDS name (longer ok)
  as select from mara
{ key mara.matnr, mara.mtart }

" After activation:
" SE11 shows: ZMAT_V (read-only database view)
" SE16N: data via ZMAT_V or ZCDS_MATERIAL_HEADER
" Eclipse ADT: edit only via ZCDS_MATERIAL_HEADER

" Real conversion result:
" Before: Database view + manual OData + ABAP AUTH check
" After: CDS view with everything built in

@OData.publish: true           " Eliminates SEGW work
@AccessControl.authorizationCheck: #CHECK  " Eliminates AUTHORITY-CHECK
define view ZCDS_VENDOR_INVOICE
  as select from rbkp
  left outer join lfa1             " Was INNER - fixed data loss
    on rbkp.lifnr = lfa1.lifnr
{
  @UI.lineItem: [{ position: 10 }] " Eliminates Fiori config
  key rbkp.belnr,
  @UI.lineItem: [{ position: 20 }]
      lfa1.name1 as vendor_name   " NULL if no master - visible now
}

cds-views-003.codeExamples:
@AbapCatalog.sqlViewName: 'ZMAT_ANN_V'
@AbapCatalog.compiler.compareFilter: true
@AccessControl.authorizationCheck: #CHECK
@EndUserText.label: 'Material Overview'
@OData.publish: true
@UI.headerInfo: { typeName: 'Material',
                  typeNamePlural: 'Materials',
                  title: { value: 'Matnr' } }
define view ZCDS_MATERIAL_OVERVIEW
  as select from mara
  left outer join makt
    on mara.matnr = makt.matnr
    and makt.spras = $session.system_language
{
  @UI.lineItem: [{ position: 10 }]
  @UI.selectionField: [{ position: 10 }]
  @EndUserText.label: 'Material'
  key mara.matnr,
  @UI.lineItem: [{ position: 20 }]
  @UI.selectionField: [{ position: 20 }]
      mara.mtart as MaterialType,
  @UI.lineItem: [{ position: 30 }]
      makt.maktx as Description,
  @Semantics.amount.currencyCode: 'Currency'
  @UI.lineItem: [{ position: 40 }]
      mara.stprs as StandardPrice,
  @Semantics.currencyCode: true
      mara.peinh as Currency
}

