@AbapCatalog.sqlViewName: 'ZMAT_BASE_V'  " Mandatory, max 16
@AbapCatalog.compiler.compareFilter: true  " Performance hint
@AbapCatalog.preserveKey: true             " For associations
define view ZI_MATERIAL_BASE
  as select from mara
{
  key mara.matnr,  " Preserved due to preserveKey
      mara.mtart,
      mara.matkl
}
" Without preserveKey: if consumer uses this
" as association source without selecting matnr,
" join condition missing → runtime error

@Analytics.dataCategory: #CUBE
@Analytics.query: true
define view ZCDS_FI_CUBE
  as select from acdoca
  association [0..1] to t001 as _Company
    on $projection.rbukrs = _Company.bukrs
{
  key acdoca.rldnr,
  key acdoca.rbukrs as Company,
  key acdoca.racct  as GLAccount,
  @Aggregation.default: #SUM
  @Semantics.amount.currencyCode: 'Curr'
      sum(acdoca.hsl) as Amount,
  @Semantics.currencyCode: true
      acdoca.rhcur    as Curr,
      _Company
} group by acdoca.rldnr, acdoca.rbukrs,
           acdoca.racct, acdoca.rhcur

@Search.searchable: true
define view ZCDS_VENDOR_SEARCH
  as select from lfa1
{
  key lfa1.lifnr as Vendor,
  @Search.defaultSearchElement: true
  @Search.fuzzinessThreshold: 0.8
      lfa1.name1 as VendorName,
  @Search.defaultSearchElement: true
      lfa1.stras as Street,
      lfa1.land1 as Country
}
