@EndUserText.label: 'Material Overview'
define view ZCDS_MAT_TEXT_DEMO
  as select from mara
  left outer join makt
    on mara.matnr = makt.matnr
    and makt.spras = $session.system_language
{
  @EndUserText.label: 'Material Number'
  @EndUserText.quickInfo: 'Unique material identifier'
  @ObjectModel.text.element: ['Description']
  key mara.matnr as Matnr,
  @EndUserText.label: 'Material Type'
      mara.mtart as MaterialType,
  @EndUserText.label: 'Description'
  @ObjectModel.representativeKey: 'Matnr'
      makt.maktx as Description
}
